INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, 6, 1, "", "だからもっともっと頑張って\n最高のステージをすることで\nその言葉にお返しが\nできたらなって…", 11, 1060030, 112411, "", "", 1);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", 6, "", "", "", 91, 1060031, 0, "", "", "");
