INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (0, 7, 0, "", "vo_omp_7007_002", 21, 1070025, "vo_omp_7007", "", "", "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, 7, 1, "", "ペコリーヌさまの場合は、\n空腹で締め付けられていた\n可能性もありますが…", 11, 1070026, 105931, "", "", 1);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", 7, "", "", "", 91, 1070027, 0, "", "", "");
