INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (0, 7, 0, "", "vo_omp_7007_003", 21, 1070030, "vo_omp_7007", "", "", "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, 7, 1, "", "まーたしかに、あのときの\nウヅキたちのゲリラLIVEは\nほんとにボロボロだったわね！", 11, 1070031, 106031, "", "", 1);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", 7, "", "", "", 91, 1070032, 0, "", "", "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1, 7, "", "", "omp_idle_normal", 3, 1070033, 106031, 0, "", "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1, 7, "", "", "omp_talk_worry", 3, 1070034, 112611, 0, "", "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (0, 7, 0, "", "vo_omp_7007_004", 21, 1070035, "vo_omp_7007", "", "", "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, 7, 1, "", "もうっ、キャルキャル～\nあんま言わないでよ～！\n私たちだってわかってるんだからさ～", 11, 1070036, 112611, "", "", 1);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", 7, "", "", "", 91, 1070037, 0, "", "", "");
