INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1, 7, "", "", "omp_talk_normal2", 3, 1070044, 112511, 0, "", "");
